import React, { useState } from 'react';
import { Mail, MapPin, MessageCircle, Instagram, Send, Phone, Twitter, Facebook, AtSign, Briefcase, Linkedin, FileText } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';
import { toast } from 'sonner';
import { contactService } from '../services/api';

const Contact = () => {
  const { language, t } = useLanguage();
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    message: ''
  });
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!isSubmitting) {
      try {
        setIsSubmitting(true);
        await contactService.submit(formData);
        toast.success(language === 'id' ? 'Pesan berhasil dikirim!' : 'Message sent successfully!');
        setFormData({ name: '', email: '', message: '' });
      } catch (error) {
        toast.error(language === 'id' ? 'Terjadi kesalahan' : 'An error occurred');
      } finally {
        setIsSubmitting(false);
      }
    }
  };

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  return (
    <div className="min-h-screen pt-20">
      {/* Header */}
      <section className="py-16 bg-gradient-to-b from-[#F5F3F0] to-white">
        <div className="container mx-auto px-4 sm:px-6 lg:px-8 text-center">
          <h1 className="text-5xl sm:text-6xl font-serif font-light text-[#2C2C2C] mb-4">
            {t.contact.title}
          </h1>
          <p className="text-lg text-[#8B7D6B] mb-4">{t.contact.subtitle}</p>
          <div className="w-24 h-1 bg-gradient-to-r from-[#5E936C] to-[#93DA97] mx-auto" />
        </div>
      </section>

      {/* Contact Content */}
      <section className="py-16 bg-white">
        <div className="container mx-auto px-4 sm:px-6 lg:px-8">
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
            {/* Contact Form */}
            <div className="bg-[#FAF9F7] rounded-2xl p-8 shadow-lg">
              <h2 className="text-3xl font-serif font-light text-[#2C2C2C] mb-6">
                {t.contact.send}
              </h2>
              <form onSubmit={handleSubmit} className="space-y-6">
                <div>
                  <label htmlFor="name" className="block text-sm font-medium text-[#2C2C2C] mb-2">
                    {t.contact.name}
                  </label>
                  <input
                    type="text"
                    id="name"
                    name="name"
                    value={formData.name}
                    onChange={handleChange}
                    required
                    className="w-full px-4 py-3 rounded-lg border border-[#D4C4B0] bg-white focus:outline-none focus:ring-2 focus:ring-[#5E936C] focus:border-transparent transition-all duration-300"
                  />
                </div>

                <div>
                  <label htmlFor="email" className="block text-sm font-medium text-[#2C2C2C] mb-2">
                    {t.contact.email}
                  </label>
                  <input
                    type="email"
                    id="email"
                    name="email"
                    value={formData.email}
                    onChange={handleChange}
                    required
                    className="w-full px-4 py-3 rounded-lg border border-[#D4C4B0] bg-white focus:outline-none focus:ring-2 focus:ring-[#5E936C] focus:border-transparent transition-all duration-300"
                  />
                </div>

                <div>
                  <label htmlFor="message" className="block text-sm font-medium text-[#2C2C2C] mb-2">
                    {t.contact.message}
                  </label>
                  <textarea
                    id="message"
                    name="message"
                    value={formData.message}
                    onChange={handleChange}
                    required
                    rows="5"
                    className="w-full px-4 py-3 rounded-lg border border-[#D4C4B0] bg-white focus:outline-none focus:ring-2 focus:ring-[#5E936C] focus:border-transparent transition-all duration-300 resize-none"
                  />
                </div>

                <button
                  type="submit"
                  disabled={isSubmitting}
                  className="w-full flex items-center justify-center space-x-2 px-6 py-3 bg-gradient-to-r from-[#5E936C] to-[#3E5F44] text-white rounded-lg font-medium tracking-wide uppercase text-sm hover:shadow-lg hover:shadow-[#5E936C]/30 transform hover:scale-105 transition-all duration-300 disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  <Send className="w-4 h-4" />
                  <span>{isSubmitting ? (language === 'id' ? 'Mengirim...' : 'Sending...') : t.contact.send}</span>
                </button>
              </form>
            </div>

            {/* Contact Info */}
            <div className="space-y-6">
              {/* Location & Map */}
              <div className="bg-white rounded-2xl p-6 shadow-lg hover:shadow-2xl transition-shadow duration-500">
                <div className="flex items-center gap-4 mb-4">
                  <div className="w-12 h-12 rounded-full bg-gradient-to-br from-[#5E936C] to-[#3E5F44] flex items-center justify-center">
                    <MapPin className="w-6 h-6 text-white" />
                  </div>
                  <div>
                    <h3 className="text-xl font-serif text-[#2C2C2C]">{t.contact.location}</h3>
                    <p className="text-[#8B7D6B] text-sm">{t.contact.locationText}</p>
                  </div>
                </div>
                <div className="w-full h-48 rounded-xl overflow-hidden mt-4 border border-[#D4C4B0]">
                  <iframe 
                    title="DES Location"
                    src="https://www.google.com/maps/embed?pb=!1m17!1m12!1m3!1d224.9255144730859!2d107.76853613338986!3d-7.042128122454051!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m2!1m1!2zN8KwMDInMzEuOCJTIDEwN8KwNDYnMDYuNyJF!5e1!3m2!1sen!2sid!4v1774762756885!5m2!1sen!2sid" 
                    width="100%" 
                    height="100%" 
                    style={{ border: 0 }} 
                    allowFullScreen="" 
                    loading="lazy"
                    referrerPolicy="no-referrer-when-downgrade">
                  </iframe>
                </div>
                <a href="https://maps.app.goo.gl/x3Uj3iBRgMWUxQbn7" target="_blank" rel="noreferrer" className="inline-block mt-4 text-sm text-[#5E936C] hover:underline font-medium">Buka di Google Maps →</a>
              </div>

              {/* Direct Contacts */}
              <div className="bg-white rounded-2xl p-6 shadow-lg hover:shadow-2xl transition-shadow duration-500 grid gap-4 grid-cols-1 sm:grid-cols-2">
                <a href="mailto:dailyessentialstyle@gmail.com" className="flex items-center gap-4 group p-3 rounded-xl hover:bg-[#F5F3F0] transition-colors">
                  <div className="w-10 h-10 rounded-full bg-[#F5F3F0] group-hover:bg-[#5E936C] flex items-center justify-center transition-colors">
                    <Mail className="w-4 h-4 text-[#8B7D6B] group-hover:text-white" />
                  </div>
                  <div>
                    <h4 className="text-sm font-medium text-[#2C2C2C]">Email</h4>
                    <span className="text-xs text-[#8B7D6B] max-w-[100px] truncate block" title="dailyessentialstyle@gmail.com">dailyessentialstyle...</span>
                  </div>
                </a>

                <a href="tel:+6285117689792" className="flex items-center gap-4 group p-3 rounded-xl hover:bg-[#F5F3F0] transition-colors">
                  <div className="w-10 h-10 rounded-full bg-[#F5F3F0] group-hover:bg-[#5E936C] flex items-center justify-center transition-colors">
                    <Phone className="w-4 h-4 text-[#8B7D6B] group-hover:text-white" />
                  </div>
                  <div>
                    <h4 className="text-sm font-medium text-[#2C2C2C]">Telepon</h4>
                    <span className="text-xs text-[#8B7D6B]">+6285117689792</span>
                  </div>
                </a>
              </div>

              {/* Social Media & Company Profile */}
              <div className="bg-white rounded-2xl p-6 shadow-lg hover:shadow-2xl transition-shadow duration-500">
                <h3 className="text-xl font-serif text-[#2C2C2C] mb-4">{t.contact.social}</h3>
                <div className="flex flex-wrap gap-4">
                  <a href="https://wa.me/6285117689792" target="_blank" rel="noreferrer" className="w-12 h-12 rounded-full border border-gray-200 bg-gray-50 text-gray-400 flex items-center justify-center hover:bg-[#25D366] hover:border-[#25D366] hover:text-white transition-all duration-300 shadow-sm group" aria-label="WhatsApp">
                    <MessageCircle className="w-5 h-5 group-hover:block" />
                  </a>
                  <a href="https://www.instagram.com/des.essentialss/" target="_blank" rel="noreferrer" className="w-12 h-12 rounded-full border border-gray-200 bg-gray-50 text-gray-400 flex items-center justify-center hover:bg-gradient-to-tr hover:from-[#F56040] hover:to-[#833AB4] hover:border-transparent hover:text-white transition-all duration-300 shadow-sm group" aria-label="Instagram">
                    <Instagram className="w-5 h-5" />
                  </a>
                  <a href="https://www.facebook.com/desessentialss/" target="_blank" rel="noreferrer" className="w-12 h-12 rounded-full border border-gray-200 bg-gray-50 text-gray-400 flex items-center justify-center hover:bg-[#1877F2] hover:border-[#1877F2] hover:text-white transition-all duration-300 shadow-sm group" aria-label="Facebook">
                    <Facebook className="w-5 h-5" />
                  </a>
                  <a href="https://x.com/des_essentialss" target="_blank" rel="noreferrer" className="w-12 h-12 rounded-full border border-gray-200 bg-gray-50 text-gray-400 flex items-center justify-center hover:bg-black hover:border-black hover:text-white transition-all duration-300 shadow-sm group" aria-label="X (Twitter)">
                    <Twitter className="w-5 h-5" />
                  </a>
                  <a href="https://www.threads.com/@des.essentialss" target="_blank" rel="noreferrer" className="w-12 h-12 rounded-full border border-gray-200 bg-gray-50 text-gray-400 flex items-center justify-center hover:bg-black hover:border-black hover:text-white transition-all duration-300 shadow-sm group" aria-label="Threads">
                    <AtSign className="w-5 h-5" />
                  </a>
                  <a href="https://www.linkedin.com/in/desessentials/" target="_blank" rel="noreferrer" className="w-12 h-12 rounded-full border border-gray-200 bg-gray-50 text-gray-400 flex items-center justify-center hover:bg-[#0A66C2] hover:border-[#0A66C2] hover:text-white transition-all duration-300 shadow-sm group" aria-label="LinkedIn">
                    <Linkedin className="w-5 h-5" />
                  </a>
                </div>

                <div className="mt-6 flex flex-col gap-3">
                  <a href="#" className="w-full py-3 px-4 rounded-xl border border-[#D4C4B0] text-[#2C2C2C] flex items-center justify-center gap-2 hover:bg-[#E32400] hover:border-[#E32400] hover:text-white transition-all duration-300 group font-medium text-sm">
                    <Briefcase className="w-4 h-4 text-[#8B7D6B] group-hover:hidden transition-none" />
                    <FileText className="w-4 h-4 text-white hidden group-hover:block transition-none" />
                    Unduh Company Profile
                  </a>
                  <a href="/docs/DES catalogue - Medium.pdf" download className="w-full py-3 px-4 rounded-xl border border-[#D4C4B0] text-[#2C2C2C] flex items-center justify-center gap-2 hover:bg-[#E32400] hover:border-[#E32400] hover:text-white transition-all duration-300 group font-medium text-sm shadow-sm">
                    <FileText className="w-4 h-4 text-[#8B7D6B] group-hover:text-white" />
                    Unduh Katalog Produk
                  </a>
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* WhatsApp Floating Button */}
      <a
        href="https://wa.me/6285117689792"
        target="_blank"
        rel="noopener noreferrer"
        className="fixed bottom-8 right-8 w-16 h-16 rounded-full bg-gradient-to-br from-[#25D366] to-[#128C7E] flex items-center justify-center shadow-2xl hover:shadow-[#25D366]/50 transform hover:scale-110 transition-all duration-300 z-40"
        aria-label="Chat on WhatsApp"
      >
        <MessageCircle className="w-8 h-8 text-white" />
      </a>
    </div>
  );
};

export default Contact;
